diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 17933ed03d58..6ce4bc652172 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -3717,6 +3717,19 @@ static Value *simplifyICmpWithDominatingAssume(CmpPredicate Predicate,
     }
   }

+  for (auto *AssumeBaseOp : {LHS->stripPointerCasts(), RHS->stripPointerCasts()}) {
+    for (auto &AssumeVH : Q.AC->assumptionsFor(AssumeBaseOp)) {
+      if (!AssumeVH)
+        continue;
+
+      CallInst *Assume = cast<CallInst>(AssumeVH);
+      if (std::optional<bool> Imp = isImpliedCondition(
+              Assume->getArgOperand(0), Predicate, LHS, RHS, Q.DL))
+        if (isValidAssumeForContext(Assume, Q.CxtI, Q.DT))
+          return ConstantInt::get(getCompareTy(LHS), *Imp);
+    }
+  }
+
   return nullptr;
 }

diff --git a/llvm/lib/Analysis/ValueTracking.cpp b/llvm/lib/Analysis/ValueTracking.cpp
index b6a80fef4217..e84493cc22c9 100644
--- a/llvm/lib/Analysis/ValueTracking.cpp
+++ b/llvm/lib/Analysis/ValueTracking.cpp
@@ -9426,9 +9426,16 @@ isImpliedCondICmps(CmpPredicate LPred, const Value *L0, const Value *L1,
       match(L0, m_c_Add(m_Specific(L1), m_Specific(R1))))
     return CmpPredicate::getMatching(LPred, RPred).has_value();

+  // (X - Y) != 0 implies X != Y, regardless of whether the subtraction has
+  // nowrap flags. If X == Y, then X - Y must be 0 in two's complement.
+  if (RPred == ICmpInst::ICMP_NE && match(L0, m_Sub(m_Specific(R0),
+                                                     m_Specific(R1))) &&
+      match(L1, m_Zero()))
+    return true;
+    return true;
+
   if (auto P = CmpPredicate::getMatching(LPred, RPred))
     return isImpliedCondOperands(*P, L0, L1, R0, R1);
-
   return std::nullopt;
 }

@@ -10149,13 +10156,6 @@ void llvm::findValuesAffectedByCondition(

     CmpPredicate Pred;
     Value *A, *B, *X;
-
-    if (IsAssume) {
-      AddAffected(V);
-      if (match(V, m_Not(m_Value(X))))
-        AddAffected(X);
-    }
-
     if (match(V, m_LogicalOp(m_Value(A), m_Value(B)))) {
       // assume(A && B) is split to -> assume(A); assume(B);
       // assume(!(A || B)) is split to -> assume(!A); assume(!B);
@@ -10172,8 +10172,18 @@ void llvm::findValuesAffectedByCondition(
         AddAffected(A);
         if (IsAssume)
           AddAffected(B);
+
+        Value *X, *Y;
+        // (X - Y) == C, where C != 0, also constrains X and Y because it
+        // implies X != Y. This is useful both for assumes and branch
+        // conditions.
+        if (HasRHSC && !cast<ConstantInt>(B)->isZero() &&
+            match(A, m_Sub(m_Value(X), m_Value(Y)))) {
+          AddAffected(X);
+          AddAffected(Y);
+        }
+
         if (HasRHSC) {
-          Value *Y;
           // (X & C) or (X | C).
           // (X << C) or (X >>_s C) or (X >>_u C).
           if (match(A, m_Shift(m_Value(X), m_ConstantInt())))
@@ -10203,6 +10213,13 @@ void llvm::findValuesAffectedByCondition(
               AddAffected(X);
               AddAffected(Y);
             }
+            // X - Y != 0 -> X != Y
+            if (match(A, m_Sub(m_Value(X), m_Value(Y))) &&
+                match(B, m_ConstantInt()) && !cast<ConstantInt>(B)->isZero()) {
+              AddAffected(X);
+              AddAffected(Y);
+            }
+
             // X nuw- Y u> C -> X u> C
             if (match(A, m_NUWSub(m_Value(X), m_Value())))
               AddAffected(X);
@@ -10221,6 +10238,7 @@ void llvm::findValuesAffectedByCondition(

       if (HasRHSC && match(A, m_Intrinsic<Intrinsic::ctpop>(m_Value(X))))
         AddAffected(X);
+        AddAffected(X);
