  9575 | // Returns a pair (Condition, ConditionIsTrue), where Condition is a branch
  9576 | // condition dominating ContextI or nullptr, if no condition is found.
  9577 | static std::pair<Value *, bool>
  9578 | getDomPredecessorCondition(const Instruction *ContextI) {
  9579 |   if (!ContextI || !ContextI->getParent())
  9580 |     return {nullptr, false};
  9581 | 
  9582 |   // TODO: This is a poor/cheap way to determine dominance. Should we use a
  9583 |   // dominator tree (eg, from a SimplifyQuery) instead?
  9584 |   const BasicBlock *ContextBB = ContextI->getParent();
  9585 |   const BasicBlock *PredBB = ContextBB->getSinglePredecessor();
  9586 |   if (!PredBB)
  9587 |     return {nullptr, false};
  9588 | 
  9589 |   // We need a conditional branch in the predecessor.
  9590 |   Value *PredCond;
  9591 |   BasicBlock *TrueBB, *FalseBB;
  9592 |   if (!match(PredBB->getTerminator(), m_Br(m_Value(PredCond), TrueBB, FalseBB)))
  9593 |     return {nullptr, false};
  9594 | 
  9595 |   // The branch should get simplified. Don't bother simplifying this condition.
  9596 |   if (TrueBB == FalseBB)
  9597 |     return {nullptr, false};
  9598 | 
  9599 |   assert((TrueBB == ContextBB || FalseBB == ContextBB) &&
  9600 |          "Predecessor block does not point to successor?");
  9601 | 
  9602 |   // Is this condition implied by the predecessor condition?
  9603 |   return {PredCond, TrueBB == ContextBB};
  9604 | }
